{{ ((chartType) => ( 
  (() => {
    const fixedRowCount = 80; 
    const data = C360_Usage.data; 

    if (!data || data.length === 0) {
      return { series: [] }; 
    }

    const last30Weekdays = [];
    let currentDate = new Date();

    while (last30Weekdays.length < 60) {
      const dayOfWeek = currentDate.getDay();
      if (dayOfWeek !== 0 && dayOfWeek !== 6) {
        last30Weekdays.push(currentDate.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' }));
      } currentDate.setDate(currentDate.getDate() - 1);
    }
    last30Weekdays.reverse();

    const actualUsers = [...new Set(data.map(item => item.user_owner_name))].sort().slice(0, fixedRowCount);

    const userToIndexMap = new Map();
    actualUsers.forEach((user, index) => {
      userToIndexMap.set(user, index);
    });

    const yAxisLabels = [...actualUsers];
    while (yAxisLabels.length < fixedRowCount) {
      yAxisLabels.push('');
    }

    const dailyCounts = {};
    data.forEach(row => {
      const dateStr = row.timestamp.split(" ")[0];
      const userName = row.user_owner_name;
      if (!dailyCounts[dateStr]) dailyCounts[dateStr] = {};
      if (!dailyCounts[dateStr][userName]) dailyCounts[dateStr][userName] = 0;
      dailyCounts[dateStr][userName]++;
    });

    const heatmapData = [];
    let maxCount = 0; 

    Object.keys(dailyCounts).forEach(dateStr => {
      Object.keys(dailyCounts[dateStr]).forEach(userName => {
        const dayIndex = last30Weekdays.indexOf(dateStr);
        const userIndex = userToIndexMap.get(userName);
        const count = dailyCounts[dateStr][userName];

        if (dayIndex > -1 && userIndex !== undefined) {
          heatmapData.push([dayIndex, userIndex, count]);
        }
        if (count > maxCount) maxCount = count;
      });
    });

    return {
      tooltip: {
        position: 'top',
        formatter: (params) => {
          if (!params || !params.value || !yAxisLabels[params.value[1]]) return '';
          const userName = yAxisLabels[params.value[1]];
          const date = last30Weekdays[params.value[0]];
          const count = params.value[2];
          return `${userName}<br/>${date}: <strong>${count}</strong>`;
        }
      },
      grid: {
        top: '1%',      // Verringert den Abstand oben
        bottom: '5%',  // Verringert den Abstand unten
        left: '2%',
        right: '2%',
        containLabel: true 
      },
      xAxis: {
        type: 'category',
        position: 'top',
        data: last30Weekdays,
        splitArea: { show: true },
        axisLabel: { interval: 0, rotate: 90 }
      },
      yAxis: {
        type: 'category',
        data: yAxisLabels,
        inverse: true,
        splitArea: { show: true }
      },
      visualMap: {
        min: 0,
        max: maxCount,
        calculable: true,
        orient: 'horizontal',
        left: 'center',
        bottom: '1%',
        inRange: {
          color: ['#f5c7dd', '#ec66a7', '#c84182'] 
        }
      },
      series: [{
        name: 'User-Aktivität',
        type: 'heatmap',
        data: heatmapData,
        label: {
          show: true,
          formatter: (params) => {
            if (!params || !params.value) return '';
            return params.value[2] > 0 ? params.value[2] : '';
          }
        }
      }]
    };
  })()
))(Activity_Chart_overview.chartType) }}
